INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('iPhone 15 Pro Max 256GB', 'iPhone 15 Pro Max 256GB 旗舰登场！搭载业界首款3nm工艺A17 Pro芯片，性能狂飙再升级，游戏、创作、多任务处理行云流水。钛金属机身轻盈坚固，搭配超视网膜XDR显示屏，色彩更鲜活，细节更锐利。Pro级摄像头系统，捕捉震撼光影瞬间，长焦端拍摄能力再突破。iOS 17系统加持，隐私安全与流畅体验双重保障，256GB大存储轻松容纳精彩生活。科技与美学的完美融合，开启你的旗舰新体验！', 9999.0, 11999, 'https://s.coze.cn/image/_gbVFw9Q_Sk/', '数码', 999, 26301, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('AirPods Pro 第二代', 'AirPods Pro 第二代，苹果真无线降噪耳机，搭载全新H2芯片，带来更强降噪性能与通透模式。主动降噪深度升级，隔绝外界纷扰；自适应通透模式智能调节环境音，对话更自然。空间音频技术打造沉浸式听感，搭配动态头部追踪，声场如临现场。续航持久，单次充电可使用6小时，搭配充电盒总续航达30小时。支持MagSafe无线充电，使用更便捷。IPX4防水防汗，运动无忧。全新设计贴合耳型，佩戴稳固舒适，重新定义无线降噪体验。', 1899.0, 2279, 'https://s.coze.cn/image/U68zf-9xCMs/', '数码', 999, 18819, 4.5, false);
