INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('真无线蓝牙耳机 黑色', '【真无线蓝牙耳机 黑色】蓝牙5.3极速连接，低延迟游戏影音更沉浸！IPX5级防水，运动出汗/雨天通勤无惧泼溅。28小时超长续航，单次满电使用8小时，搭配充电仓告别电量焦虑。半入耳式人体工学设计，佩戴稳固舒适，久戴不痛。高清通话降噪，通话清晰无杂音。轻巧便携，一手掌握，黑色经典百搭，随时随地开启无线自由！', 299.0, 359, 'https://s.coze.cn/image/CnM45qBdT5A/', '数码', 999, 16106, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('头戴式降噪耳机', '【40mm大动圈+35dB主动降噪】沉浸式音乐体验来袭！强劲40mm大动圈单元，低频澎湃、高频清亮，细节纤毫毕现。35dB深度降噪黑科技，一键隔绝通勤喧嚣/办公室干扰，图书馆/地铁秒变专属音乐舱。柔软蛋白皮耳罩+记忆棉填充，久戴无压；轻量化机身+可折叠设计，出行便携无忧。蓝牙5.3低延迟，追剧游戏音画同步，开启你的「无界降噪」音乐之旅！', 599.0, 719, 'https://s.coze.cn/image/TIdu22OtCKw/', '数码', 999, 32873, 4.5, false);
