INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('阿迪达斯运动裤', '阿迪达斯运动裤采用高弹透气面料，贴合身形又不失活动自由，无论是跑步健身还是日常休闲都能舒适应对。经典简约设计搭配品牌标志性细节，轻松适配多种穿搭风格。腰部弹性抽绳设计，自由调节松紧度，运动时稳固不滑落，日常穿着更自在。耐磨抗皱面料，久穿不易变形，让你在运动与生活场景中都能保持利落有型。', 299.0, 359, 'https://s.coze.cn/image/ng-odSUVsPA/', '服饰', 999, 45313, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('优衣库 休闲长裤', '【优衣库休闲长裤】精选100%纯棉面料，柔软透气不闷热，直筒修身剪裁适配各种身形，日常通勤、休闲出街都能轻松驾驭。简约百搭的设计，搭配T恤、衬衫都出彩，无论是单穿还是叠穿都很有质感，让你舒适自在又不失时尚感，轻松打造随性高级的日常穿搭！', 179.0, 215, 'https://s.coze.cn/image/_KQT9Ve3_U4/', '服饰', 999, 147435, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('三只松鼠坚果礼盒', '三只松鼠坚果礼盒，精选10种优质坚果，每一颗都饱满香脆！包含巴旦木、核桃、腰果等多种美味，科学配比营养更均衡。独立小包装设计，干净卫生，随时随地享受美味。无论是节日送礼、走亲访友，还是居家分享，都是贴心之选，让你轻松传递心意与美味！', 128.0, 154, 'https://s.coze.cn/image/qXMWf6kAIQU/', '美食', 999, 351035, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('良品铺子肉脯礼盒', '【良品铺子肉脯礼盒】精选三种经典风味：原味咸香醇厚、黑胡椒微辣过瘾、藤椒麻辣鲜香！严选优质猪肉后腿肉，经黄金配比腌制，慢火烘烤锁住肉汁，每一片都肉质紧实Q弹，咸甜适中不腻口。独立小包装设计，干净卫生，追剧、办公、茶歇随时解馋！无论是自食还是送礼都超有面，快把这份‘肉香盛宴’带回家吧~', 98.0, 118, 'https://s.coze.cn/image/3zRakLnq86U/', '美食', 999, 430323, 4.5, true);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('百草味每日坚果', '【百草味每日坚果30包装】精选7种优质坚果果干，科学配比营养更均衡！每天一小包，轻松补充蛋白质、膳食纤维和不饱和脂肪酸~独立小包装干净卫生，上班/追剧/健身随时开袋即食，锁住新鲜好滋味。无论是早餐搭配还是办公室零食，都是健康轻食的贴心选择，给忙碌生活注入满满活力！', 79.0, 95, 'https://s.coze.cn/image/VY3aalU1i6U/', '美食', 999, 458439, 4.5, true);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('来伊份蜜饯果干', '来伊份蜜饯果干精选多种天然鲜果，酸甜交织的美妙滋味在舌尖绽放！每一颗果干都保留着果肉的饱满与营养，无多余添加更安心。无论是办公室解馋、午后小憩，还是追剧时光，都是您的绝佳伴侣。独立小包装设计，方便携带，随时随地享受这份自然馈赠的甜蜜与清爽。', 68.0, 82, 'https://s.coze.cn/image/O8A5MqRJyn4/', '美食', 999, 355000, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('卫龙辣条大礼包', '【卫龙辣条大礼包20包】经典川香麻辣暴击味蕾！精选小麦粉+优质辣椒，传统工艺发酵更入味，Q弹劲道越嚼越香。独立小包装干净便携，追剧/办公/聚会随时解馋，一口回到童年辣条魂！囤货必备的解馋神器，辣度适中不呛喉，好吃到停不下来！', 39.0, 47, 'https://s.coze.cn/image/IYns_GW0Tok/', '美食', 999, 344184, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('稻香村月饼礼盒', '【稻香村经典广式月饼礼盒】8枚精致装，传承百年工艺，一口解锁广式甜香精髓！精选小麦粉酥皮，包裹绵密内馅，莲蓉蛋黄咸甜交织，五仁果仁醇厚饱满，每一口都是老味道的安心与满足。中秋团圆送礼/自食佳品，传统铁罐包装尽显大气，佳节氛围拉满，把这份“稻”香心意带回家！', 168.0, 202, 'https://s.coze.cn/image/6d2y8ebFF5A/', '美食', 999, 56593, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('广州酒家蛋黄酥', '【广州酒家蛋黄酥】精选海鸭咸蛋黄，搭配绵密豆沙内馅，酥皮层次分明如云朵般轻盈。一口咬下，酥皮簌簌飘落，咸香蛋黄与清甜豆馅在舌尖交融，甜而不腻，咸香适口。传统工艺手工开酥，层层起酥入口即化，每一口都是广式点心的经典风味，早餐配茶、午后解馋、馈赠亲友的绝佳选择，让味蕾邂逅岭南风情的醇厚滋味。', 58.0, 70, 'https://s.coze.cn/image/nJanvfK4beM/', '美食', 999, 310900, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('五芳斋粽子礼盒', '【五芳斋粽子礼盒】嘉兴非遗工艺匠心打造！10只经典组合（内含鲜肉粽、蛋黄肉粽、豆沙粽等），精选糯米Q弹饱满，咸甜交织风味十足。真空锁鲜包装，开袋即食方便快捷，传统箬叶包裹清香四溢，每一口都是地道嘉兴味！端午送礼/家庭分享绝佳选择，传承百年好滋味，让团圆时刻更添仪式感！', 138.0, 166, 'https://s.coze.cn/image/oGPugPR_t5k/', '美食', 999, 422638, 4.5, true);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('三全速冻水饺', '三全速冻水饺（猪肉白菜馅），传承经典家常风味！精选新鲜猪肉与脆嫩白菜黄金配比，皮薄如纸却韧性十足，一口咬开满满都是饱满馅料，鲜香肉汁瞬间迸发。0添加防腐剂，锁鲜工艺锁住食材本味，无需解冻直接下锅，煮制3-5分钟即可享用。早餐快手餐、夜宵暖心食，速冻锁鲜更省心，让美味无需等待，轻松满足全家味蕾需求！', 32.0, 38, 'https://s.coze.cn/image/tXaFCfohLbc/', '美食', 999, 483977, 4.5, true);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('思念手打鱼丸', '【思念手打鱼丸】严选深海野生鲜鱼，拒绝冷冻边角料！老师傅手工捶打8小时，保留鱼肉90%以上活性蛋白，颗颗Q弹似弹珠，咬开瞬间鲜汁迸发！0淀粉添加，低脂高蛋白，老人小孩都能放心吃。煮汤、火锅、烧烤随心搭配，热辣鲜香一口沦陷，让每一餐都充满海洋的鲜甜暴击！', 28.0, 34, 'https://s.coze.cn/image/__bpACuL_dE/', '美食', 999, 204025, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('康师傅红烧牛肉面', '康师傅红烧牛肉面5连包，经典红烧风味传承多年！浓郁醇厚的红烧汤底，精选劲道面条，搭配Q弹卤蛋与鲜香配料，一口唤醒味蕾记忆。开水冲泡3分钟即享热乎美味，无论是匆忙早餐、加班简餐还是解馋时刻，都是你的暖心选择。独立包装干净卫生，囤货必备，让美味随时相伴！', 25.0, 30, 'https://s.coze.cn/image/JJtKFQr8H7I/', '美食', 999, 174794, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('统一老坛酸菜面', '统一老坛酸菜面，传承经典老坛发酵工艺！精选优质酸菜，酸爽开胃，辣得过瘾，一口唤醒味蕾！劲道面条Q弹爽滑，搭配浓郁汤底，每一口都是地道川味享受。5连包超值组合，早餐、夜宵、加班党必备，随时随地来一碗，满足你的胃！', 25.0, 30, 'https://s.coze.cn/image/6Lj6RqpFzh0/', '美食', 999, 394033, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('螺霸王螺蛳粉', '【螺霸王螺蛳粉3袋装】正宗柳州风味！精选广西螺蛳慢火熬制金汤，醇厚鲜香；Q弹爽滑米粉搭配酸笋、花生、腐竹等7种配料，酸香浓郁，辣而不燥。开袋即煮，10分钟享地道嗦粉快乐，囤3袋更划算！让你足不出户，随时随地解馋过瘾！', 45.0, 54, 'https://s.coze.cn/image/ea8eMLl27Cw/', '美食', 999, 406342, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('李子柒螺蛳粉', '🔥李子柒螺蛳粉｜网红爆款再升级！地道柳州风味，料包多到溢出来！劲道米粉裹满浓郁螺蛳汤底，搭配Q弹腐竹、酸笋、花生、木耳、酸豆角等6大配料，一口嗦出酸辣鲜香！古法熬制汤底，鲜而不腥，辣而不燥，还原街头巷尾的地道嗦粉快乐！独立包装干净卫生，冷水下锅10分钟即享，懒人速食也能吃出仪式感，追剧解馋必备神器！', 52.0, 62, 'https://s.coze.cn/image/2ByS05hhRGE/', '美食', 999, 357569, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('海底捞自热火锅', '🔥海底捞自热火锅，地道牛油麻辣锅底，一口点燃味蕾！精选优质食材，搭配Q弹蔬菜、嫩滑豆制品，分量超足吃到爽。15分钟自热即食，无需开火，随时随地享受火锅自由。独立小包装干净卫生，聚会、加班、追剧必备，让你足不出户也能get海底捞同款美味！', 39.0, 47, 'https://s.coze.cn/image/97-c4TqgxuI/', '美食', 999, 140185, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('自嗨锅自热火锅', '【自嗨锅麻辣牛肉自热火锅】随时随地开涮！精选大块麻辣牛肉，搭配Q弹宽粉、爽脆蔬菜，秘制麻辣汤底鲜香过瘾。无需开火，冷水加热15分钟即享热气腾腾的火锅盛宴，独立小包装干净便携，加班、追剧、户外出游必备！一人食也能轻松get的火锅自由，让美味随时随地“嗨”起来～', 35.0, 42, 'https://s.coze.cn/image/B5_GNEHHCEQ/', '美食', 999, 86372, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('旺旺雪饼 700g', '【旺旺雪饼700g】童年记忆里的香脆滋味！精选优质大米，传统工艺烘烤非油炸，入口酥松化渣，米香浓郁不甜腻。独立小包装设计，干净卫生易携带，无论是宅家追剧、办公室解馋，还是出游分享都超合适。经典白绿包装唤醒满满回忆杀，每一口都是童年的味道，囤上一箱，快乐加倍！', 35.0, 42, 'https://s.coze.cn/image/e9_EhDrvUK4/', '美食', 999, 206982, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('旺旺仙贝 700g', '【旺旺仙贝700g】经典童年味道升级回归！精选优质大米与小麦粉，经传统工艺烘焙，每一口都是咸香酥脆的极致体验。独立小包装设计，干净卫生易携带，无论是宅家追剧、朋友聚会，还是办公室解馋，都是绝佳搭档。严选原料配比，咸度适中不齁，米香浓郁层层迸发，酥脆口感让人欲罢不能。700g大容量分享装，全家共享更满足，囤货必备的经典零食，唤醒味蕾记忆的美味选择！', 32.0, 38, 'https://s.coze.cn/image/2fY9NOmseXo/', '美食', 999, 359990, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('奥利奥夹心饼干', '奥利奥经典巧克力夹心饼干，一口咬下酥香四溢！外层饼干采用优质小麦粉烘焙，口感松脆不粘牙；内部夹着浓郁丝滑的巧克力奶油，甜而不腻，层次丰富。传承百年工艺，经典配方带来熟悉的幸福味道，无论是早餐搭配牛奶，还是午后休闲解馋，都是绝佳选择。独立小包装设计，方便携带分享，随时随地享受美味时光~', 25.0, 30, 'https://s.coze.cn/image/u64wROmk4ZQ/', '美食', 999, 261678, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('好吃点坚果饼干', '好吃点坚果饼干，精选饱满核桃与香脆杏仁，黄金配比融入酥松饼身！每一口都能咬到真实坚果颗粒，口感层次丰富，酥而不腻。传统工艺烘焙，保留坚果原香与营养，早餐搭配牛奶、下午茶解馋小食，健康美味双在线！独立小包装设计，随时随地享受酥脆好滋味，追剧、办公都超合适~', 22.0, 26, 'https://s.coze.cn/image/r4Xq9hwfd0Y/', '美食', 999, 147849, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('达利园法式小面包', '达利园法式小面包，一口咬下松软如云，麦香与清甜在舌尖交融。独立小包装设计，干净卫生，随时随地都能享受这份甜蜜。早餐搭配牛奶开启元气一天，午后小憩来一块补充能量，追剧解馋也超合适，是你生活中不可或缺的美味小确幸。', 28.0, 34, 'https://s.coze.cn/image/vnqU2k6WiDQ/', '美食', 999, 71984, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('盼盼法式软面包', '盼盼法式软面包，每一口都是云朵般的绵软细腻！精选优质小麦粉，搭配天然乳源，发酵工艺锁住浓郁奶香。撕开面包体，蓬松组织细腻如丝，入口即化不粘牙，甜而不腻的醇厚麦香在舌尖绽放。独立小包装设计，便携又卫生，早餐、下午茶、加班解馋都合适，让你随时随地享受法式烘焙的浪漫美味，开启元气满满的一天！', 19.0, 23, 'https://s.coze.cn/image/KRGa1xCD7LU/', '美食', 999, 243519, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('百威啤酒 12罐', '【百威啤酒12罐】经典清爽口感，精选优质麦芽与啤酒花，入口麦香醇厚，泡沫细腻持久。冰镇后饮用，瞬间唤醒味蕾，是朋友聚会、家庭小酌的绝佳伴侣。12罐规格满足多人分享需求，随时随地畅饮无忧，为欢乐时刻注入冰爽活力！', 88.0, 106, 'https://s.coze.cn/image/0nMKTucgsUg/', '美食', 999, 73905, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('青岛啤酒 12罐', '【青岛啤酒12罐】百年匠心酿造，国民信赖的经典滋味！精选优质原料与传统工艺，酒体清亮澄澈，泡沫细腻持久，入口甘醇爽口，麦香与酒香完美融合。无论是朋友小聚、家庭分享，还是独酌放松，开一罐冰镇的青岛啤酒，瞬间唤醒味蕾，畅饮每一刻的惬意！12罐超值装，随时随地享受纯粹啤酒乐趣，品质之选，不容错过！', 68.0, 82, 'https://s.coze.cn/image/R_wbyemO9RY/', '美食', 999, 438687, 4.5, true);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('雪花啤酒 12罐', '雪花啤酒12罐装，清爽淡爽口感，年轻潮流之选！精选优质原料，入口顺滑，泡沫细腻持久，带来冰爽畅饮体验。无论是朋友聚会、夏日消暑，还是独自小酌，都能轻松适配，开启愉悦时光。每一口都是纯粹麦香与清爽回甘的完美融合，是你日常休闲、社交场合的绝佳拍档。', 58.0, 70, 'https://s.coze.cn/image/bcCFld1ejnw/', '美食', 999, 93758, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('农夫山泉矿泉水', '农夫山泉天然矿泉水，源自大自然馈赠，每一滴都蕴含天然矿物质精华。水质清冽甘甜，口感纯净柔和，满足日常补水需求。24瓶整箱装，方便储存与携带，无论是居家饮用、办公解渴还是户外出行，都是您的安心之选。坚持天然水源地直采，品质稳定可靠，为健康生活保驾护航。', 48.0, 58, 'https://s.coze.cn/image/iWIeZJwSQVc/', '美食', 999, 109114, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('怡宝纯净水', '怡宝纯净水，源自严格品控的生产工艺，口感纯净无味，每一口都带来清爽体验。24瓶整箱装，满足家庭日常、办公饮用等多种场景需求，随时随地畅饮安心好水。优质水源+科学净化技术，品质值得信赖，是您健康饮水的贴心选择。', 45.0, 54, 'https://s.coze.cn/image/kdt7P8TCyjw/', '美食', 999, 209434, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('可口可乐 24罐', '【可口可乐24罐整箱】经典碳酸饮料，每一口都迸发鲜活气泡！源自百年配方，甜而不腻的焦糖香气与清爽口感完美融合，冰饮后瞬间唤醒味蕾，驱散夏日燥热与疲惫。无论是家庭聚会、朋友畅饮还是独自放松，24罐足量规格满足你对快乐气泡的所有想象，随时随地畅饮无忧，开启活力满满的快乐时光！', 59.0, 71, 'https://s.coze.cn/image/KSFTe9wwUpE/', '美食', 999, 490974, 4.5, true);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('百事可乐 24罐', '【百事可乐24罐】经典清爽气泡水，每一口都迸发鲜活活力！甜度恰到好处，不齁不腻，搭配美食解腻又过瘾。冰镇后饮用，气泡在舌尖炸开，瞬间唤醒味蕾，带来畅爽体验。24罐大容量装，家庭分享、聚会畅饮都合适，随时随地享受这份快乐！', 55.0, 66, 'https://s.coze.cn/image/thrDhas4v7s/', '美食', 999, 360935, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('元气森林气泡水', '【元气森林白桃味气泡水】0糖0脂的清爽新选择！精选阳光白桃原香，搭配细腻气泡在舌尖迸发，每一口都是轻盈畅快的味觉盛宴。0负担配方，让你尽情享受甜润果香，无论是宅家追剧、办公提神，还是运动后解渴，都是你的元气搭档～一口唤醒活力，开启轻负担的健康生活！', 79.0, 95, 'https://s.coze.cn/image/lGKFydar0Lk/', '美食', 999, 155493, 4.5, false);
