INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('特仑苏纯牛奶', '【特仑苏纯牛奶】源自黄金奶源带，每一滴都凝聚天然牧场的纯净能量。精选优质奶牛，科学饲养铸就卓越品质，蛋白质含量高达3.6g/100ml，远超国家标准，醇厚营养轻松吸收。从牧场到餐桌全程锁鲜，口感丝滑浓郁，自然奶香萦绕舌尖。无论是早餐搭配、午后补给，还是睡前滋养，都是您高品质生活的安心之选，让健康与美味时刻相伴！', 68.0, 82, 'https://s.coze.cn/image/TOrh-Y8kUWY/', '美食', 999, 114201, 4.5, false);
