INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('安慕希希腊酸奶', '【安慕希希腊酸奶】严选优质奶源，采用希腊传统发酵工艺，成就浓稠醇厚的丝滑质地！每一口都像云朵般绵密，0蔗糖添加更健康，富含优质蛋白质，为身体注入满满活力。早餐搭配面包、下午茶轻食、运动后补充能量，随时随地享受纯粹美味与营养守护，让健康生活从一杯好酸奶开始！', 58.0, 70, 'https://s.coze.cn/image/JIwQa0vzCfk/', '美食', 999, 433486, 4.5, true);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('纯甄酸奶', '纯甄酸奶，以纯净配方为初心，严选优质奶源，每一口都是无添加的安心之味。细腻醇厚的口感，酸甜平衡恰到好处，给味蕾温柔拥抱。无多余添加，保留酸奶本真风味，无论是早餐搭配面包，还是午后休闲小食，都能带来纯粹的美味享受，让健康与美味轻松同行。', 52.0, 62, 'https://s.coze.cn/image/kN0aG8ujqWI/', '美食', 999, 420794, 4.5, true);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('德芙丝滑巧克力', '德芙丝滑巧克力，甄选优质可可原料，以精湛工艺打造丝滑醇厚的味觉盛宴。入口瞬间，细腻质地如丝绸般融化，浓郁可可香气在舌尖缓缓释放，甜度恰到好处，余韵悠长。独立小包装设计，随时随地开启甜蜜时刻，无论是犒赏自己还是分享美好，都是绝佳选择。每一块都凝聚着德芙对品质的执着，带给你纯粹而愉悦的味蕾享受。', 45.0, 54, 'https://s.coze.cn/image/Q_Xxodn7cYk/', '美食', 999, 351345, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('费列罗金莎巧克力', '【费列罗金莎巧克力】经典榛仁夹心，每一口都藏着丝滑惊喜！外层裹着金箔质感的脆米巧克力，咬开瞬间榛仁的醇厚香气与丝滑内馅完美交融，甜而不腻的味觉盛宴。金箔包装精致奢华，无论是犒赏自己还是馈赠亲友，都尽显心意与品味。开启甜蜜时刻，让舌尖沉醉于这颗‘金莎’的浪漫魔力～', 118.0, 142, 'https://s.coze.cn/image/mX0y_NuSruw/', '美食', 999, 202434, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('好时KISSES巧克力', '【好时KISSES巧克力】经典水滴造型，每一颗都像被施了魔法的甜蜜小水滴！独立小包装设计，干净卫生，随时随地开启甜蜜时光。丝滑浓郁的巧克力口感，入口即化，醇厚可可香气在舌尖绽放，甜而不腻，幸福感瞬间拉满。无论是休闲解馋、办公提神，还是分享给朋友、装点派对，都是绝佳选择。快来把这份‘吻’住的甜蜜带回家吧！', 48.0, 58, 'https://s.coze.cn/image/ip6UWYwQeXw/', '美食', 999, 90290, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('徐福记沙琪玛', '徐福记沙琪玛，一口咬下松软如云，蛋香在舌尖层层绽放！精选优质小麦粉与鲜鸡蛋黄金配比，传统工艺慢火烘烤，入口即化却不失韧性。香甜不腻的口感，搭配酥软蓬松的质地，每一口都是纯粹的享受。无论是早餐搭配牛奶，还是午后休闲解馋，亦或是加班提神小食，都是绝佳选择。独立包装设计，干净卫生，随时随地满足你的味蕾渴望，开启甜蜜好时光！', 32.0, 38, 'https://s.coze.cn/image/jnd9k1AAQug/', '美食', 999, 78199, 4.5, false);
