INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('旺仔牛奶 24罐', '旺仔牛奶24罐组合装，经典甜牛奶风味，醇厚香甜，大人小孩都爱喝！采用优质奶源，搭配科学配方，口感顺滑，营养美味。无论是早餐搭配面包，还是午后休闲小酌，亦或是作为家庭聚会的饮品，都是绝佳选择。24罐大容量包装，满足全家日常饮用需求，随时随地享受这份甜蜜与温暖。', 78.0, 94, 'https://s.coze.cn/image/Lqr_ujrPUr4/', '美食', 999, 339942, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('老干妈风味豆豉', '【老干妈风味豆豉】国民级下饭神器！精选贵州优质大豆发酵，搭配鲜辣豆豉与秘制香辛料，经传统工艺慢火熬制，酱香浓郁、咸香适口。颗粒分明的豆豉裹挟着醇厚油香，拌饭时拌入一勺，米饭瞬间迸发层次感；拌面条、蘸馒头、炒青菜……百搭吃法解锁无限美味，开瓶即食超方便，轻松拯救没胃口的餐桌！', 25.0, 30, 'https://s.coze.cn/image/erOMe8rOUYk/', '美食', 999, 176339, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('海天金标生抽', '海天金标生抽，精选优质原料，传统工艺与现代技术结合，鲜味醇厚自然，咸鲜适口。炒菜提鲜、凉拌增香、蘸食提味，一瓶搞定多种烹饪场景，是厨房调味的必备之选，让家常菜也能轻松出彩，为您的餐桌增添美味。', 35.0, 42, 'https://s.coze.cn/image/Rf4XbM_nCvM/', '美食', 999, 51622, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('李锦记蚝油', '李锦记蚝油，精选优质生蚝熬制，蚝香浓郁醇厚，每一滴都饱含海洋鲜韵。提鲜增味效果显著，无论是炒菜、炖煮还是蘸食，只需少许便能点亮菜品风味，让家常菜也能拥有餐厅级的鲜美体验。传统工艺与现代技术结合，品质稳定，是厨房提鲜的绝佳伴侣，为您的每一餐增添丰富口感与层次。', 38.0, 46, 'https://s.coze.cn/image/ZpCM1PvUKdI/', '美食', 999, 318129, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('双汇王中王火腿肠', '【双汇王中王火腿肠】经典国民美味，30年品质传承！精选优质猪肉为主料，肉质紧实弹牙，咸香适口不腻。黄金配比工艺锁住肉汁，每一口都饱满多汁。独立小包装设计，早餐煎烤、泡面搭档、户外零食随心享，国民信赖的安心之选，让美味随时随地相伴！', 18.0, 22, 'https://s.coze.cn/image/-DO9UIltjR0/', '美食', 999, 445045, 4.5, true);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('金锣肉多多火腿肠', '金锣肉多多火腿肠，真材实料看得见！精选优质猪肉，含肉量超高，每一口都能吃到满满的肉香。Q弹爽滑的口感，肉质紧实有嚼劲，无论是早餐煎烤、泡面搭档，还是追剧解馋，都是绝佳选择。开袋即食，方便快捷，让美味随时相伴，是您餐桌上的贴心小食，更是忙碌生活的能量补给站！', 22.0, 26, 'https://s.coze.cn/image/CsHEtReZrUc/', '美食', 999, 406023, 4.5, false);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('乐事薯片原味', '乐事原味薯片，传承经典配方！精选优质马铃薯，黄金比例调味，每一片都薄脆酥香，入口即化。咸香适中不腻，一口唤醒味蕾，追剧、聚会、休闲时刻的绝佳搭档！独立包装干净卫生，分享更自在，让快乐随时在线！', 35.0, 42, 'https://s.coze.cn/image/8mxzQKhBj3s/', '美食', 999, 462814, 4.5, true);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('可比克薯片番茄味', '可比克番茄味薯片，精选阳光番茄与优质马铃薯黄金配比！酸甜浓郁的番茄酱汁均匀裹满每一片薯片，入口瞬间迸发清新果香，轻咬即酥脆掉渣，咸甜交织的绝妙口感在舌尖层层绽放。独立小包装设计，无论是办公解馋、追剧分享还是朋友聚会，都能随时随地享受这份“咔嚓”脆响的快乐。0反式脂肪酸配方，美味无负担，让你轻松get童年回忆里的经典味道！', 28.0, 34, 'https://s.coze.cn/image/CRgDoAJJ8Mk/', '美食', 999, 489865, 4.5, true);
INSERT INTO products (name, description, price, original_price, image_url, category, stock, sales_count, rating, is_hot) VALUES ('三只松鼠夏威夷果', '三只松鼠夏威夷果，每一颗都经过精挑细选！个大饱满的果仁，轻轻一剥就能露出完整的果核，奶香四溢的独特风味，入口酥脆又带着天然的清甜。精选优质产地原料，保留坚果最本真的营养与口感，无论是追剧休闲还是办公解馋，都是绝佳选择。独立小包装设计，干净卫生，方便携带，随时随地享受这份来自大自然的馈赠！', 59.0, 71, 'https://s.coze.cn/image/nOPrNolrWTc/', '美食', 999, 376561, 4.5, false);